+            det.process_frame(&phases, &amps);
+        }
+
+        // Now send perfectly flat amplitudes (all identical, nonzero).
+        let flat_amps = [1.0f32; 16]; // variance = 0 < MIN_AMPLITUDE_VARIANCE
