+        m_ph /= n as f32; m_a /= n as f32;
+        let mut a_var = 0.0f32;
+        for i in 0..n { let d = amps[i] - m_a; a_var += d * d; }
+        a_var /= n as f32;
+
+        // ── Calibration ─────────────────────────────────────────────────
+        if !self.calibrated {
+            self.cal_amp += m_a;
+            self.cal_var += a_var;
+            self.cal_n += 1;
+            if !self.amps_init {
+                for i in 0..n { self.prev_amps[i] = amps[i]; }
+                self.amps_init = true;
+            }
+            if self.cal_n >= BASELINE_FRAMES {
+                let cnt = self.cal_n as f32;
