+
+        // ── 2. Injection ────────────────────────────────────────────────
+        let inj_f = if self.amps_init {
+            let mut jc = 0u32;
+            for i in 0..n {
+                if self.prev_amps[i] > 0.0001 && amps[i] / self.prev_amps[i] > INJECTION_FACTOR {
+                    jc += 1;
+                }
+            }
+            jc as f32 / n as f32
+        } else { 0.0 };
